import './App.css';
import "@radix-ui/themes/styles.css";
import { Theme, ThemePanel, Box, Container, Button, Flex, Text, Section, Heading} from "@radix-ui/themes";

function App() {
  return (
    <Theme accentColor="yellow" panelBackground="solid" radius="full">
      <Box style={{ background: "var(--gray-a2)", borderRadius: "var(--radius-3)" }}>
        <Container size="3">
          <Box>
            <Section size="5">
              <Flex direction="column" gap="2">
                <Heading as="h1">Ted Fawke</Heading>
                <ThemePanel />
              </Flex>
            </Section>
          </Box>
        </Container>
      </Box>
    </Theme>
  );
}

export default App;
